import React, { useEffect, Suspense, lazy } from "react";
import "./HomePage.css";
import Loading from "../Loading/Loading";

// 1. استيراد المكونات بشكل كسول (Lazy Loading)
// هذا يقلل حجم التحميل الأولي للموقع بشكل كبير
const Home = lazy(() => import("../../Components/Home/Home"));

function HomePage() {
  useEffect(() => {
    // التمرير للأعلى عند دخول الصفحة
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, []);

  return (
    <div className="background">
      {/* 2. استخدام Suspense لعرض صفحة التحميل أثناء جلب المكونات والبيانات */}
      <Suspense fallback={<Loading />}>
        {/* ملاحظة: يفضل استيراد البيانات داخل المكون Home نفسه 
            أو تمريرها من هنا إذا كانت ثابتة.
        */}
        <Home />
      </Suspense>
    </div>
  );
}

export default React.memo(HomePage);
